1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	interface Customer {
12	  yearsWithMHPCO: number;
13	}
14	
15	interface QuoteResult {
16	  premium: number;
17	}
18	
19	const BLOCK_SIZE = 3;
20	const BLOCK_PRICE = 60;
21	
22	const quotePremium = (items: Array<{ type: string }>): number => {
23	  const counts: Record<string, number> = {};
24	  for (const item of items) {
25	    counts[item.type] = (counts[item.type] ?? 0) + 1;
26	  }
27	  let total = 0;
28	  for (const [type, count] of Object.entries(counts)) {
29	    if (count === BLOCK_SIZE) {
30	      total += BLOCK_PRICE;
31	    } else {
32	      total += count * (BASE_PREMIUMS[type] ?? 0);
33	    }
34	  }
35	  return total + PROCESSING_FEE;
36	};
37	
38	export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<{ type: string }> }>): Array<QuoteResult> =>
39	  steps.map((step) => ({
40	    premium: quotePremium(step.items),
41	  }));
